import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../api/axios';

const STATUS_COLOR = {
  Pending: { bg: '#fef3c7', color: '#92400e' },
  Approved: { bg: '#d1fae5', color: '#065f46' },
  Rejected: { bg: '#fee2e2', color: '#991b1b' },
  Waiting: { bg: '#e0e7ff', color: '#3730a3' },
};

export default function ExpenseDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [expense, setExpense] = useState(null);

  useEffect(() => {
    api.get(`/expenses/${id}`).then((res) => setExpense(res.data));
  }, [id]);

  if (!expense) return <div style={{ padding: '2rem', fontFamily: 'sans-serif' }}>Loading...</div>;

  const lines = expense.ocrData?.expenseLines || [];
  const total = lines.reduce((s, l) => s + (l.amount || 0), 0) || expense.amount;

  return (
    <div style={s.page}>
      <button onClick={() => navigate(-1)} style={s.back}>← Back</button>

      {/* Expense Info Card */}
      <div style={s.card}>
        <div style={s.cardHeader}>
          <div>
            <h2 style={{ margin: 0 }}>Expense Details</h2>
            <span style={{ color: '#6b7280', fontSize: '0.9rem' }}>
              Submitted by {expense.employee?.name} on {new Date(expense.createdAt).toLocaleDateString()}
            </span>
          </div>
          <span style={{ ...s.badge, ...STATUS_COLOR[expense.status] }}>{expense.status}</span>
        </div>

        <div style={s.infoGrid}>
          <div style={s.infoItem}><span style={s.infoLabel}>Vendor</span><span>{expense.ocrData?.vendor || '—'}</span></div>
          <div style={s.infoItem}><span style={s.infoLabel}>Expense Type</span><span>{expense.category}</span></div>
          <div style={s.infoItem}><span style={s.infoLabel}>Date</span><span>{new Date(expense.date).toLocaleDateString()}</span></div>
          <div style={s.infoItem}><span style={s.infoLabel}>Currency</span><span>{expense.currency}</span></div>
          <div style={s.infoItem}><span style={s.infoLabel}>Amount</span><span style={{ fontWeight: 700, color: '#4f46e5' }}>{expense.currency} {Number(expense.amount).toFixed(2)}</span></div>
          <div style={s.infoItem}><span style={s.infoLabel}>Converted</span><span>{expense.convertedCurrency} {Number(expense.convertedAmount).toFixed(2)}</span></div>
        </div>

        {expense.description && (
          <div style={{ marginTop: '1rem' }}>
            <span style={s.infoLabel}>Description</span>
            <p style={{ margin: '0.3rem 0 0', color: '#374151' }}>{expense.description}</p>
          </div>
        )}

        {expense.receiptUrl && (
          <div style={{ marginTop: '1rem' }}>
            <a href={`/${expense.receiptUrl}`} target="_blank" rel="noreferrer" style={{ color: '#4f46e5' }}>
              📎 View Receipt
            </a>
          </div>
        )}
      </div>

      {/* Expense Lines Table */}
      {lines.length > 0 && (
        <div style={s.card}>
          <h3 style={s.sectionTitle}>Expense Lines</h3>
          <table style={s.table}>
            <thead>
              <tr style={s.thead}>
                <th style={s.th}>Item / Description</th>
                <th style={{ ...s.th, textAlign: 'right' }}>Amount</th>
              </tr>
            </thead>
            <tbody>
              {lines.map((l, i) => (
                <tr key={i} style={s.tr}>
                  <td style={s.td}>{l.description}</td>
                  <td style={{ ...s.td, textAlign: 'right' }}>{Number(l.amount).toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr>
                <td style={{ ...s.td, fontWeight: 700 }}>Total</td>
                <td style={{ ...s.td, textAlign: 'right', fontWeight: 700, color: '#4f46e5' }}>
                  {expense.currency} {Number(total).toFixed(2)}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      )}

      {/* Approval Chain */}
      <div style={s.card}>
        <h3 style={s.sectionTitle}>Approval Progress</h3>
        <div style={s.timeline}>
          {expense.approvals.map((a, i) => {
            const sc = STATUS_COLOR[a.status];
            return (
              <div key={i} style={s.timelineItem}>
                <div style={{ ...s.dot, background: sc.color }} />
                {i < expense.approvals.length - 1 && <div style={s.line} />}
                <div style={s.timelineContent}>
                  <div style={s.timelineHeader}>
                    <span style={{ fontWeight: 600 }}>Step {a.step} — {a.approverId?.name}</span>
                    <span style={{ ...s.badge, ...sc, fontSize: '0.75rem' }}>{a.status}</span>
                  </div>
                  <span style={{ fontSize: '0.82rem', color: '#6b7280' }}>{a.approverId?.role}</span>
                  {a.comment && <p style={s.comment}>"{a.comment}"</p>}
                  {a.actionAt && (
                    <span style={{ fontSize: '0.78rem', color: '#9ca3af' }}>
                      {new Date(a.actionAt).toLocaleString()}
                    </span>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

const s = {
  page: { maxWidth: '760px', margin: '2rem auto', padding: '0 1rem', fontFamily: 'sans-serif' },
  back: { background: 'none', border: 'none', color: '#4f46e5', cursor: 'pointer', fontSize: '0.95rem', marginBottom: '1rem', padding: 0 },
  card: { background: '#fff', borderRadius: '10px', padding: '1.5rem', boxShadow: '0 1px 4px rgba(0,0,0,0.08)', marginBottom: '1.25rem' },
  cardHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1.25rem' },
  badge: { padding: '0.25rem 0.8rem', borderRadius: '999px', fontSize: '0.82rem', fontWeight: 600 },
  infoGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '1rem' },
  infoItem: { display: 'flex', flexDirection: 'column', gap: '0.2rem' },
  infoLabel: { fontSize: '0.75rem', fontWeight: 700, color: '#9ca3af', textTransform: 'uppercase' },
  sectionTitle: { margin: '0 0 1rem', fontSize: '1rem', fontWeight: 700, color: '#374151' },
  table: { width: '100%', borderCollapse: 'collapse' },
  thead: { background: '#f9fafb' },
  th: { padding: '0.6rem 0.75rem', fontSize: '0.78rem', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', borderBottom: '1px solid #e5e7eb', textAlign: 'left' },
  tr: { borderBottom: '1px solid #f3f4f6' },
  td: { padding: '0.6rem 0.75rem', fontSize: '0.9rem' },
  timeline: { display: 'flex', flexDirection: 'column', gap: 0 },
  timelineItem: { display: 'flex', gap: '1rem', position: 'relative', paddingBottom: '1.25rem' },
  dot: { width: '12px', height: '12px', borderRadius: '50%', marginTop: '4px', flexShrink: 0 },
  line: { position: 'absolute', left: '5px', top: '16px', bottom: 0, width: '2px', background: '#e5e7eb' },
  timelineContent: { flex: 1, display: 'flex', flexDirection: 'column', gap: '0.2rem' },
  timelineHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center' },
  comment: { margin: '0.3rem 0 0', fontStyle: 'italic', color: '#6b7280', fontSize: '0.85rem' },
};
